 60→long EpiCenters::minCoordinatedEpiCenter(const Matter *matter,
 61→                                         double neighborCutoff) {
 62→  bool *minCoordinatedList;
 63→  long j, nAtoms, indexEpiCenter, minCoordinationVal;
 64→  double tempDouble;
 65→  nAtoms = matter->numberOfAtoms();
 66→  minCoordinatedList = new bool[nAtoms];
 67→  indexEpiCenter = -2; // initialize to a value that will fail the assert if no
 68→                       // EpiCenter is found
 69→  //----- Initialize end -----
 70→  // std::cout<<"minCoordinatedEpiCenter\n";
 71→
 72→  minCoordinationVal = minCoordination(matter, neighborCutoff);
 73→  coordinationLessOrEqual(minCoordinatedList, minCoordinationVal, matter,
 74→                          neighborCutoff);
 75→
 76→  // count all atoms that are minimally coordinated and free to move
 77→  j = 0;
 78→  for (int i = 0; i < nAtoms; i++) {
 79→    if ((minCoordinatedList[i]) && !(matter->getFixed(i)))
 80→      j++;
 81→  }
 82→  // pick a random atom that is free and minimally coordinated
 83→  tempDouble = randomDouble(j);
 84→  j = (long)tempDouble;
 85→  for (int i = 0; i < nAtoms; i++) {
 86→    if ((minCoordinatedList[i]) && !(matter->getFixed(i))) {
 87→      if (!j) {
 88→        indexEpiCenter = i;
 89→        break;
 90→      } else
 91→        j--;
 92→    }
 93→  }
 94→  delete[] minCoordinatedList;
 95→
 96→  // make certain the chosen atom is in the atom list
 97→  assert(indexEpiCenter > -1 && indexEpiCenter < nAtoms);
 98→  return (indexEpiCenter);
 99→}
