149→void EpiCenters::cna(long *cna, const Matter *matter, double neighborCutoff) {
150→  int a1 = 0;
151→  int a2 = 0;
152→  int a3 = 0;
153→  int nAtoms;
154→  int unsigned n = 0;
155→  int unsigned n1 = 0;
156→  int unsigned n2 = 0;
157→  int unsigned m2 = 0;
158→  int j1 = 0;
159→  int j2 = 0;
160→  double diffR;
161→  int nBonds = 0;
162→  int bondsSum = 0;
163→  nAtoms = (int)matter->numberOfAtoms();
164→  vector<int> nFCC(nAtoms);
165→  vector<int> nHCP(nAtoms);
166→  vector<vector<int>> neighborLists(nAtoms);
167→  //----- Initialize end -----
168→  // std::cout<<"cna\n";
169→
170→  for (int i = 0; i < nAtoms - 1; i++) {
171→    for (int j = i + 1; j < nAtoms; j++) {
172→      diffR = matter->distance(i, j);
173→      if (diffR < neighborCutoff) {
174→        neighborLists[i].push_back(j);
175→        neighborLists[j].push_back(i);
176→      }
177→    }
178→  }
179→  for (a2 = 0; a2 < nAtoms; a2++) {
180→    vector<int> &nbs2 = neighborLists[a2];
181→    for (n2 = 0; n2 < nbs2.size(); n2++) {
182→      a1 = nbs2[n2];
183→      if (a1 < a2) {
184→        vector<int> common;
185→        vector<int> &nbs1 = neighborLists[a1];
186→        for (n1 = 0; n1 < nbs1.size(); n1++) {
187→          a3 = nbs1[n1];
188→          for (m2 = 0; m2 < nbs2.size(); m2++)
189→            if (a3 == nbs2[m2])
190→              common.push_back(a3);
191→        }
192→        if (common.size() == 4) {
193→          nBonds = 0;
194→          bondsSum = 0;
195→          for (j2 = 1; j2 < 4; j2++) {
196→            vector<int> &nbs = neighborLists[common[j2]];
197→            for (j1 = 0; j1 < j2; j1++) {
198→              for (n = 0; n < nbs.size(); n++) {
199→                if (common[j1] == nbs[n]) {
200→                  nBonds++;
201→                  bondsSum += j1 + j2;
202→                  break;
203→                }
204→              }
205→            }
206→          }
207→          if (nBonds == 2) {
208→            if (bondsSum == 6) {
209→              nFCC[a1]++;
210→              nFCC[a2]++;
211→            } else {
212→              nHCP[a1]++;
213→              nHCP[a2]++;
214→            }
215→          }
216→        }
217→      }
218→    }
219→  }
220→  // 0: fcc (421), 1: hcp (422), 2: other
221→  for (int i = 0; i < nAtoms; i++) {
222→    if (neighborLists[i].size() == 12) {
223→      if (nFCC[i] == 12)
224→        cna[i] = 0;
225→      else if (nFCC[i] == 6 && nHCP[i] == 6)
226→        cna[i] = 1;
227→      else
228→        cna[i] = 2;
229→    } else
230→      cna[i] = 2;
231→  }
232→  return;
233→}
234→
235→void EpiCenters::coordination(long *coordinationVal, const Matter *matter,
236→                              double neighborCutoff) {
237→  long nAtoms;
238→  double diffR;
239→  nAtoms = matter->numberOfAtoms();
240→  for (int i = 0; i < nAtoms; i++)
241→    coordinationVal[i] = 0;
242→  //----- Initialize end -----
243→  // std::cout<<"coordination\n";
244→
245→  for (int i = 0; i < nAtoms - 1; i++) {
246→    for (int j = i + 1; j < nAtoms; j++) {
247→      // determine coordination number
248→      diffR = matter->distance(i, j);
249→      if (diffR < neighborCutoff) {
250→        coordinationVal[i] = coordinationVal[i] + 1;
251→        coordinationVal[j] = coordinationVal[j] + 1;
252→      }
253→    }
254→  }
255→  return;
256→}
257→
258→void EpiCenters::coordinationLessOrEqual(bool *result, long coordinationMaxVal,
259→                                         const Matter *matter,
260→                                         double neighborCutoff) {
261→  long *coordinationVal;
262→  long nAtoms;
263→  nAtoms = matter->numberOfAtoms();
264→  coordinationVal = new long[nAtoms];
265→  //----- Initialize end -----
266→  // std::cout<<"coordinationLessOrEqual\n";
267→
268→  coordination(coordinationVal, matter, neighborCutoff);
269→
270→  for (int i = 0; i < nAtoms; i++) {
271→    if ((coordinationVal[i] < coordinationMaxVal + 1) && !(matter->getFixed(i)))
272→      result[i] = true;
273→    else
274→      result[i] = false;
275→  }
276→  delete[] coordinationVal;
277→
278→  return;
279→}
280→
281→long EpiCenters::minCoordination(const Matter *matter, double neighborCutoff) {
282→  long *coordinationVal;
283→  long nAtoms;
284→  long minCoordinationVal;
285→  nAtoms = matter->numberOfAtoms();
286→  coordinationVal = new long[nAtoms];
287→  //----- Initialize end -----
288→  // std::cout<<"minCoordination\n";
289→
290→  coordination(coordinationVal, matter, neighborCutoff);
291→  // LONG_MAX is a the maximal value a long can achieve, from library limits
292→  minCoordinationVal = LONG_MAX;
293→
294→  for (int i = 0; i < nAtoms; i++) {
295→    if ((coordinationVal[i] < minCoordinationVal) && !(matter->getFixed(i))) {
296→      minCoordinationVal = coordinationVal[i];
297→    }
298→  }
299→  delete[] coordinationVal;
300→
301→  return (minCoordinationVal);
302→}
