 22→std::vector<std::string> SaddleSearchJob::run(void) {
 23→  string reactantFilename("pos.con");
 24→  string displacementFilename("displacement.con");
 25→  string modeFilename("direction.dat");
 26→
 27→  if (params.main_options.checkpoint) {
 28→    FILE *disp, *mode;
 29→    disp = fopen("displacement_cp.con", "r");
 30→    mode = fopen("mode_cp.dat", "r");
 31→    if (disp != NULL && mode != NULL) {
 32→      displacementFilename = "displacement_cp.con";
 33→      modeFilename = "mode_cp.dat";
 34→      SPDLOG_LOGGER_DEBUG(log, "Resuming from checkpoint");
 35→    } else {
 36→      SPDLOG_LOGGER_DEBUG(log, "No checkpoint files found");
 37→    }
 38→  }
 39→
 40→  initial = std::make_shared<Matter>(pot, params);
 41→  displacement = std::make_shared<Matter>(pot, params);
 42→  saddle = std::make_shared<Matter>(pot, params);
 43→
 44→  initial->con2matter(reactantFilename);
 45→
 46→  if (params.saddle_search_options.displace_type == EpiCenters::DISP_LOAD) {
 47→    // displacement was passed from the server
 48→    saddle->con2matter(displacementFilename);
 49→  } else {
 50→    // displacement and mode will be made on the client
 51→    // in saddleSearch->initialize(...)
 52→    *saddle = *initial;
 53→  }
 54→  AtomMatrix mode;
 55→  if (params.saddle_search_options.displace_type == EpiCenters::DISP_LOAD) {
 56→    // mode was passed from the server
 57→    mode = helper_functions::loadMode(modeFilename, initial->numberOfAtoms());
 58→  }
 59→
 60→  saddleSearch = std::make_unique<MinModeSaddleSearch>(
 61→      saddle, mode, initial->getPotentialEnergy(), params, pot);
 62→
 63→  int status;
 64→  status = doSaddleSearch();
 65→  printEndState(status);
 66→  saveData(status);
 67→
 68→  return returnFiles;
 69→}
 70→
 71→int SaddleSearchJob::doSaddleSearch() {
 72→  Matter matterTemp(pot, params);
 73→  long status;
 74→  int f1{0};
 75→  f1 = this->pot->forceCallCounter;
 76→  try {
 77→    status = saddleSearch->run();
 78→  } catch (int e) {
 79→    if (e == 100) {
 80→      status = MinModeSaddleSearch::STATUS_POTENTIAL_FAILED;
 81→    } else {
 82→      printf("unknown exception: %i\n", e);
 83→      throw e;
 84→    }
 85→  }
 86→
 87→  if (params.saddle_search_options.minmode_method ==
 88→      LowestEigenmode::MINMODE_GPRDIMER) {
 89→    fCallsSaddle = saddleSearch->forcecalls - f1; // TODO: Check if this
 90→    // works
 91→  } else {
 92→    fCallsSaddle += this->pot->forceCallCounter - f1;
 93→  }
 94→
 95→  return status;
 96→}
