150→void SaddleSearchJob::printEndState(int status) {
151→  SPDLOG_LOGGER_DEBUG(log, "[Saddle Search] Final status: ");
152→
153→  if (status == MinModeSaddleSearch::STATUS_GOOD)
154→    SPDLOG_LOGGER_DEBUG(log, "Success");
155→
156→  else if (status == MinModeSaddleSearch::STATUS_BAD_NO_CONVEX)
157→    SPDLOG_LOGGER_DEBUG(log,
158→                        "Initial displacement unable to reach convex region");
159→
160→  else if (status == MinModeSaddleSearch::STATUS_BAD_HIGH_ENERGY)
161→    SPDLOG_LOGGER_DEBUG(log, "Barrier too high");
162→
163→  else if (status == MinModeSaddleSearch::STATUS_BAD_MAX_CONCAVE_ITERATIONS)
164→    SPDLOG_LOGGER_DEBUG(log, "Too many iterations in concave region");
165→
166→  else if (status == MinModeSaddleSearch::STATUS_BAD_MAX_ITERATIONS)
167→    SPDLOG_LOGGER_DEBUG(log, "Too many iterations");
168→
169→  else if (status == MinModeSaddleSearch::STATUS_BAD_NOT_CONNECTED)
170→    SPDLOG_LOGGER_DEBUG(log, "Saddle is not connected to initial state");
171→
172→  else if (status == MinModeSaddleSearch::STATUS_BAD_PREFACTOR)
173→    SPDLOG_LOGGER_DEBUG(log, "Prefactors not within window");
174→
175→  else if (status == MinModeSaddleSearch::STATUS_FAILED_PREFACTOR)
176→    SPDLOG_LOGGER_DEBUG(log, "Hessian calculation failed");
177→
178→  else if (status == MinModeSaddleSearch::STATUS_BAD_HIGH_BARRIER)
179→    SPDLOG_LOGGER_DEBUG(log, "Energy barrier not within window");
180→
181→  else if (status == MinModeSaddleSearch::STATUS_BAD_MINIMA)
182→    SPDLOG_LOGGER_DEBUG(log, "Minimizations from saddle did not converge");
183→
184→  else if (status == MinModeSaddleSearch::STATUS_NONNEGATIVE_ABORT)
185→    SPDLOG_LOGGER_DEBUG(log, "Nonnegative initial mode, aborting");
186→
187→  else if (status == MinModeSaddleSearch::STATUS_NEGATIVE_BARRIER)
188→    SPDLOG_LOGGER_DEBUG(log, "Negative barrier detected");
189→
190→  else if (status == MinModeSaddleSearch::STATUS_BAD_MD_TRAJECTORY_TOO_SHORT)
191→    SPDLOG_LOGGER_DEBUG(log, "No reaction found during MD trajectory");
192→
193→  else if (status == MinModeSaddleSearch::STATUS_BAD_NO_NEGATIVE_MODE_AT_SADDLE)
194→    SPDLOG_LOGGER_DEBUG(
195→        log, "Converged to stationary point with zero negative modes");
196→
197→  else if (status == MinModeSaddleSearch::STATUS_BAD_NO_BARRIER)
198→    SPDLOG_LOGGER_DEBUG(log,
199→                        "No forward barrier was found along minimized band");
200→
201→  else if (status == MinModeSaddleSearch::STATUS_ZEROMODE_ABORT)
202→    SPDLOG_LOGGER_DEBUG(log, "Zero mode abort.");
203→
204→  else if (status == MinModeSaddleSearch::STATUS_OPTIMIZER_ERROR)
205→    SPDLOG_LOGGER_DEBUG(log, "Optimizer error.");
206→
207→  else
208→    SPDLOG_LOGGER_DEBUG(log, "Unknown status: {}!", status);
209→
210→  return;
211→}
