 24→std::vector<std::string> ProcessSearchJob::run(void) {
 25→  string reactantFilename("pos.con");
 26→  string displacementFilename("displacement.con");
 27→  string modeFilename("direction.dat");
 28→  size_t fctmp{0}; // force call temporary
 29→  initial = std::make_shared<Matter>(pot, params);
 30→  if (params.saddle_search_options.method == "min_mode" ||
 31→      params.saddle_search_options.method == "basin_hopping" ||
 32→      params.saddle_search_options.method == "bgsd") {
 33→    displacement = std::make_shared<Matter>(pot, params);
 34→  } else if (params.saddle_search_options.method == "dynamics") {
 35→    displacement = NULL;
 36→  }
 37→  saddle = std::make_shared<Matter>(pot, params);
 38→  min1 = std::make_shared<Matter>(pot, params);
 39→  min2 = std::make_shared<Matter>(pot, params);
 40→
 41→  if (!initial->con2matter(reactantFilename)) {
 42→    printf("Stop\n");
 43→    exit(1);
 44→  }
 45→
 46→  if (params.process_search_options.minimize_first) {
 47→    SPDLOG_LOGGER_DEBUG(log, "Minimizing initial structure\n");
 48→    fctmp = initial->getPotentialCalls();
 49→    initial->relax();
 50→    fCallsMin += initial->getPotentialCalls() - fctmp;
 51→    SPDLOG_LOGGER_DEBUG(log, "Initial minimization took {} fcalls",
 52→                        initial->getPotentialCalls() - fctmp);
 53→  }
 54→
 55→  barriersValues[0] = barriersValues[1] = 0;
 56→  prefactorsValues[0] = prefactorsValues[1] = 0;
 57→
 58→  if (params.saddle_search_options.method == "min_mode" ||
 59→      params.saddle_search_options.method == "basin_hopping" ||
 60→      params.saddle_search_options.method == "bgsd") {
 61→    if (params.saddle_search_options.displace_type == EpiCenters::DISP_LOAD) {
 62→      // displacement was passed from the server
 63→      if (!saddle->con2matter(displacementFilename)) {
 64→        printf("Stop\n");
 65→        exit(1);
 66→      }
 67→      *min1 = *min2 = *initial;
 68→    } else {
 69→      // displacement and mode will be made on the client
 70→      // in SaddleSearch->initialize(...)
 71→      *saddle = *min1 = *min2 = *initial;
 72→    }
 73→  } else {
 74→    *saddle = *min1 = *min2 = *initial;
 75→  }
 76→
 77→  AtomMatrix mode;
 78→
 79→  if (params.saddle_search_options.method == "min_mode") {
 80→    if (params.saddle_search_options.displace_type == EpiCenters::DISP_LOAD) {
 81→      // mode was passed from the server
 82→      mode = helper_functions::loadMode(modeFilename, initial->numberOfAtoms());
 83→    }
 84→    saddleSearch = std::make_unique<MinModeSaddleSearch>(
 85→        saddle, mode, initial->getPotentialEnergy(), params, pot);
 86→  } else if (params.saddle_search_options.method == "basin_hopping") {
 87→    saddleSearch =
 88→        std::make_unique<BasinHoppingSaddleSearch>(min1, saddle, pot, params);
 89→  } else if (params.saddle_search_options.method == "dynamics") {
 90→    saddleSearch = std::make_unique<DynamicsSaddleSearch>(saddle, params);
 91→  } else if (params.saddle_search_options.method == "bgsd") {
 92→    saddleSearch = std::make_unique<BiasedGradientSquaredDescent>(
 93→        saddle, initial->getPotentialEnergy(), params);
 94→  }
 95→
 96→  int status = doProcessSearch();
 97→
 98→  printEndState(status);
 99→  saveData(status);
100→
101→  // might have been forced to be equal if the structure passed to the client
102→  // when determining barrier and the prefactor
103→
104→  return returnFiles;
105→}
106→
107→int ProcessSearchJob::doProcessSearch(void) {
108→  Matter matterTemp(pot, params);
109→  long status;
110→  size_t fctmp{0};
111→
112→  fctmp = pot->forceCallCounter;
113→  status = saddleSearch->run();
114→  fCallsSaddle += pot->forceCallCounter - fctmp;
115→  SPDLOG_DEBUG("Got {} calls in the saddle search, with previous {}",
116→               fCallsSaddle, fctmp);
117→
118→  if (status != MinModeSaddleSearch::STATUS_GOOD) {
119→    return status;
120→  }
121→
122→  // relax from the saddle point
123→
124→  AtomMatrix posSaddle = saddle->getPositions();
125→  AtomMatrix displacedPos;
126→
127→  *min1 = *saddle;
128→
129→  displacedPos =
130→      posSaddle - saddleSearch->getEigenvector() *
131→                      params.process_search_options.minimization_offset;
132→  min1->setPositions(displacedPos);
133→
134→  SPDLOG_LOGGER_DEBUG(log, "Starting Minimization 1");
135→  fctmp = min1->getPotentialCalls();
136→  bool converged =
137→      min1->relax(false, params.debug_options.write_movies, false, "min1");
138→  fCallsMin += min1->getPotentialCalls() - fctmp;
139→  SPDLOG_LOGGER_DEBUG(log, "Min1 minimization took {} fcalls",
140→                      min1->getPotentialCalls() - fctmp);
141→
142→  if (!converged) {
143→    return MinModeSaddleSearch::STATUS_BAD_MINIMA;
144→  }
145→
146→  *min2 = *saddle;
147→  displacedPos =
148→      posSaddle + saddleSearch->getEigenvector() *
149→                      params.process_search_options.minimization_offset;
150→  min2->setPositions(displacedPos);
151→
152→  SPDLOG_LOGGER_DEBUG(log, "Starting Minimization 2");
153→  fctmp = min2->getPotentialCalls();
154→  converged =
155→      min2->relax(false, params.debug_options.write_movies, false, "min2");
156→  fCallsMin += min2->getPotentialCalls() - fctmp;
157→  SPDLOG_LOGGER_DEBUG(log, "Min2 minimization took {} fcalls",
158→                      min2->getPotentialCalls() - fctmp);
159→
160→  if (!converged) {
161→    return MinModeSaddleSearch::STATUS_BAD_MINIMA;
162→  }
163→
164→  // if min2 corresponds to initial state, swap min1 && min2
165→  if (!(initial->compare(*min1)) && initial->compare(*min2)) {
166→    matterTemp = *min1;
167→    *min1 = *min2;
168→    *min2 = matterTemp;
169→  }
170→
171→  if ((initial->compare(*min1)) == false) {
172→    SPDLOG_LOGGER_DEBUG(log, "initial != min1");
173→    return MinModeSaddleSearch::STATUS_BAD_NOT_CONNECTED;
174→  }
175→
176→  if (initial->compare(*min2)) {
177→    // both minima are the initial state
178→    SPDLOG_LOGGER_DEBUG(log, "both minima are the initial state");
179→    return MinModeSaddleSearch::STATUS_BAD_NOT_CONNECTED;
180→  }
181→
182→  // use the structure passed to the client when determining
183→  // the barrier and prefactor for the forward process
184→  if (!params.process_search_options.minimize_first) {
185→    min1 = initial;
186→  }
187→
188→  // Calculate the barriers
189→  barriersValues[0] = saddle->getPotentialEnergy() - min1->getPotentialEnergy();
190→  barriersValues[1] = saddle->getPotentialEnergy() - min2->getPotentialEnergy();
191→
192→  if ((params.saddle_search_options.max_energy < barriersValues[0]) ||
193→      (params.saddle_search_options.max_energy < barriersValues[1])) {
194→    return MinModeSaddleSearch::STATUS_BAD_HIGH_BARRIER;
195→  }
196→
197→  if (barriersValues[0] < 0.0 || barriersValues[1] < 0.0) {
198→    return MinModeSaddleSearch::STATUS_NEGATIVE_BARRIER;
199→  }
200→
201→  // calculate the prefactor
202→  if (!params.prefactor_options.default_value) {
203→    fctmp = min1->getPotentialCalls();
204→    int prefStatus;
205→    double pref1, pref2;
206→    // XXX: no get() calls
207→    prefStatus = Prefactor::getPrefactors(params, min1.get(), saddle.get(),
208→                                          min2.get(), pref1, pref2);
209→    if (prefStatus == -1) {
210→      printf("Prefactor: bad calculation\n");
211→      return MinModeSaddleSearch::STATUS_FAILED_PREFACTOR;
212→    }
213→    fCallsPrefactors += min1->getPotentialCalls() - fctmp;
214→
215→    /* Check that the prefactors are in the correct range */
216→    if ((pref1 > params.prefactor_options.max_value) ||
217→        (pref1 < params.prefactor_options.min_value)) {
218→      cout << "Bad reactant-to-saddle prefactor: " << pref1 << endl;
219→      return MinModeSaddleSearch::STATUS_BAD_PREFACTOR;
220→    }
221→    if ((pref2 > params.prefactor_options.max_value) ||
222→        (pref2 < params.prefactor_options.min_value)) {
223→      cout << "Bad product-to-saddle prefactor: " << pref2 << endl;
224→      return MinModeSaddleSearch::STATUS_BAD_PREFACTOR;
225→    }
226→    prefactorsValues[0] = pref1;
227→    prefactorsValues[1] = pref2;
228→
229→  } else {
230→    // use the default prefactor value specified
231→    prefactorsValues[0] = params.prefactor_options.default_value;
232→    prefactorsValues[1] = params.prefactor_options.default_value;
233→  }
234→  return MinModeSaddleSearch::STATUS_GOOD;
235→}
