237→void ProcessSearchJob::saveData(int status) {
238→  FILE *fileResults, *fileReactant, *fileSaddle, *fileProduct, *fileMode;
239→
240→  std::string resultsFilename("results.dat");
241→  returnFiles.push_back(resultsFilename);
242→  fileResults = fopen(resultsFilename.c_str(), "wb");
243→  // XXX: min_fcalls isn't quite right it should get them from
244→  //      the minimizer. But right now the minimizers are in
245→  //      the SaddleSearch object. They will be taken out eventually.
246→
247→  fprintf(fileResults, "%d termination_reason\n", status);
248→  fprintf(fileResults, "%ld random_seed\n", params.main_options.randomSeed);
249→  fprintf(fileResults, "%s potential_type\n",
250→          std::string{magic_enum::enum_name<PotType>(
251→                          params.potential_options.potential)}
252→              .c_str());
253→  fprintf(fileResults, "%zu total_force_calls\n",
254→          fCallsMin + fCallsSaddle + fCallsPrefactors);
255→  fprintf(fileResults, "%zu force_calls_minimization\n", fCallsMin);
256→  //    fprintf(fileResults, "%ld force_calls_minimization\n",
257→  //    SaddleSearch->forceCallsMinimization + fCallsMin);
258→  fprintf(fileResults, "%zu force_calls_saddle\n", fCallsSaddle);
259→  fprintf(fileResults, "%.12e potential_energy_saddle\n",
260→          saddle->getPotentialEnergy());
261→  fprintf(fileResults, "%.12e potential_energy_reactant\n",
262→          min1->getPotentialEnergy());
263→  fprintf(fileResults, "%.12e potential_energy_product\n",
264→          min2->getPotentialEnergy());
265→  fprintf(fileResults, "%.12e barrier_reactant_to_product\n",
266→          barriersValues[0]);
267→  fprintf(fileResults, "%.12e barrier_product_to_reactant\n",
268→          barriersValues[1]);
269→  if (params.saddle_search_options.method == "min_mode") {
270→    fprintf(fileResults, "%.12e displacement_saddle_distance\n",
271→            displacement->perAtomNorm(*saddle));
272→  } else {
273→    fprintf(fileResults, "%.12e displacement_saddle_distance\n", 0.0);
274→  }
275→  if (params.saddle_search_options.method == "dynamics") {
276→    auto ds = dynamic_cast<DynamicsSaddleSearch &>(*saddleSearch);
277→    fprintf(fileResults, "%.12e simulation_time\n",
278→            ds.time * params.constants.timeUnit);
279→    fprintf(fileResults, "%.12e md_temperature\n",
280→            params.saddle_search_options.dynamics.temperature);
281→  }
282→  fprintf(fileResults, "%zu force_calls_prefactors\n", fCallsPrefactors);
283→  fprintf(fileResults, "%.12e prefactor_reactant_to_product\n",
284→          prefactorsValues[0]);
285→  fprintf(fileResults, "%.12e prefactor_product_to_reactant\n",
286→          prefactorsValues[1]);
287→  fclose(fileResults);
288→
289→  std::string reactantFilename("reactant.con");
290→  returnFiles.push_back(reactantFilename);
291→  fileReactant = fopen(reactantFilename.c_str(), "wb");
292→  min1->matter2con(fileReactant);
293→
294→  std::string modeFilename("mode.dat");
295→  returnFiles.push_back(modeFilename);
296→  fileMode = fopen(modeFilename.c_str(), "wb");
297→  helper_functions::saveMode(fileMode, saddle, saddleSearch->getEigenvector());
298→  fclose(fileMode);
299→  fclose(fileReactant);
300→
301→  std::string saddleFilename("saddle.con");
302→  returnFiles.push_back(saddleFilename);
303→  fileSaddle = fopen(saddleFilename.c_str(), "wb");
304→  saddle->matter2con(fileSaddle);
305→  fclose(fileSaddle);
306→
307→  std::string productFilename("product.con");
308→  returnFiles.push_back(productFilename);
309→  fileProduct = fopen(productFilename.c_str(), "wb");
310→  min2->matter2con(fileProduct);
311→  fclose(fileProduct);
312→
313→  return;
