316→void ProcessSearchJob::printEndState(int status) {
317→  SPDLOG_LOGGER_DEBUG(log, "[Saddle Search] Final status: ");
318→
319→  if (status == MinModeSaddleSearch::STATUS_GOOD)
320→    SPDLOG_LOGGER_DEBUG(log, "Success");
321→  else if (status == MinModeSaddleSearch::STATUS_BAD_NO_CONVEX)
322→    SPDLOG_LOGGER_ERROR(log,
323→                        "Initial displacement unable to reach convex region");
324→  else if (status == MinModeSaddleSearch::STATUS_BAD_HIGH_ENERGY)
325→    SPDLOG_LOGGER_ERROR(log, "Barrier too high");
326→  else if (status == MinModeSaddleSearch::STATUS_BAD_MAX_CONCAVE_ITERATIONS)
327→    SPDLOG_LOGGER_ERROR(log, "Too many iterations in concave region");
328→  else if (status == MinModeSaddleSearch::STATUS_BAD_MAX_ITERATIONS)
329→    SPDLOG_LOGGER_ERROR(log, "Too many iterations");
330→  else if (status == MinModeSaddleSearch::STATUS_BAD_NOT_CONNECTED)
331→    SPDLOG_LOGGER_ERROR(log, "Saddle is not connected to initial state");
332→  else if (status == MinModeSaddleSearch::STATUS_BAD_PREFACTOR)
333→    SPDLOG_LOGGER_ERROR(log, "Prefactors not within window");
334→  else if (status == MinModeSaddleSearch::STATUS_FAILED_PREFACTOR)
335→    SPDLOG_LOGGER_ERROR(log, "Hessian calculation failed");
336→  else if (status == MinModeSaddleSearch::STATUS_BAD_HIGH_BARRIER)
337→    SPDLOG_LOGGER_ERROR(log, "Energy barrier not within window");
338→  else if (status == MinModeSaddleSearch::STATUS_BAD_MINIMA)
339→    SPDLOG_LOGGER_ERROR(log, "Minimizations from saddle did not converge");
340→  else if (status == MinModeSaddleSearch::STATUS_NONNEGATIVE_ABORT)
341→    SPDLOG_LOGGER_CRITICAL(log, "Nonnegative initial mode, aborting");
342→  else if (status == MinModeSaddleSearch::STATUS_NEGATIVE_BARRIER)
343→    SPDLOG_LOGGER_ERROR(log, "Negative barrier detected");
344→  else if (status == MinModeSaddleSearch::STATUS_BAD_MD_TRAJECTORY_TOO_SHORT)
345→    SPDLOG_LOGGER_ERROR(log, "No reaction found during MD trajectory");
346→  else if (status == MinModeSaddleSearch::STATUS_BAD_NO_NEGATIVE_MODE_AT_SADDLE)
347→    SPDLOG_LOGGER_ERROR(
348→        log, "Converged to stationary point with zero negative modes");
349→  else if (status == MinModeSaddleSearch::STATUS_BAD_NO_BARRIER)
350→    SPDLOG_LOGGER_ERROR(log,
351→                        "No forward barrier was found along minimized band");
352→  else if (status == MinModeSaddleSearch::STATUS_ZEROMODE_ABORT)
353→    SPDLOG_LOGGER_CRITICAL(log, "Zero mode abort.");
354→  else if (status == MinModeSaddleSearch::STATUS_OPTIMIZER_ERROR)
355→    SPDLOG_LOGGER_ERROR(log, "Optimizer error.");
356→  else
357→    SPDLOG_LOGGER_ERROR(log, "Unknown status: %i!", status);
358→  return;
359→}
