 30→class MinModeObjectiveFunction : public ObjectiveFunction {
 31→private:
 32→  AtomMatrix eigenvector;
 33→  std::shared_ptr<LowestEigenmode> minModeMethod;
 34→  int iteration;
 35→
 36→public:
 37→  MinModeObjectiveFunction(std::shared_ptr<Matter> matterPassed,
 38→                           std::shared_ptr<LowestEigenmode> minModeMethodPassed,
 39→                           AtomMatrix modePassed,
 40→                           const Parameters &paramsPassed)
 41→      : ObjectiveFunction(matterPassed, paramsPassed),
 42→        minModeMethod{minModeMethodPassed} {
 43→    eigenvector = modePassed;
 44→  }
 45→
 46→  ~MinModeObjectiveFunction(void) {}
 47→
 48→  VectorXd getGradient(bool fdstep = false) {
 49→    AtomMatrix proj;
 50→    AtomMatrix force = matter->getForces();
 51→
 52→    if (!fdstep || iteration == 0) {
 53→      minModeMethod->compute(matter, eigenvector);
 54→      // Check if ImprovedDimer lost the mode immediately after compute()
 55→      auto dimer = std::dynamic_pointer_cast<ImprovedDimer>(minModeMethod);
 56→      if (dimer && !dimer->rotationDidConverge) {
 57→        // Check if it restored to a valid negative curvature state
 58→        if (dimer->getEigenvalue() < 0.0) {
 59→          // Dimer restored to best state - update eigenvector and continue
 60→          // but signal that we should probably stop soon
 61→          eigenvector = minModeMethod->getEigenvector();
 62→          SPDLOG_DEBUG(
 63→              "[MinMode] Dimer restored to best state with C_tau={:.4f}",
 64→              dimer->getEigenvalue());
 65→          throw eonc::DimerModeRestoredException();
 66→        } else {
 67→          // Truly lost - no valid state to restore to
 68→          throw eonc::DimerModeLostException();
 69→        }
 70→      }
 71→      iteration++;
 72→    }
 73→
 74→    eigenvector = minModeMethod->getEigenvector();
 75→    double eigenvalue = minModeMethod->getEigenvalue();
 76→
 77→    proj =
 78→        (force.array() * eigenvector.array()).sum() * eigenvector.normalized();
 79→
 80→    if (0 < eigenvalue) {
 81→      if (params.saddle_search_options.perp_force_ratio > 0.0) {
 82→        // reverse force parallel to eigenvector, and reduce perpendicular force
 83→        double const d = params.saddle_search_options.perp_force_ratio;
 84→        force = d * force - (1. + d) * proj;
 85→
 86→        // zero out the smallest forces to keep displacement confined
 87→      } else if (params.saddle_search_options.confine_positive.enabled) {
 88→        if (params.saddle_search_options.confine_positive.bowl_breakout) {
 89→          AtomMatrix forceTemp = matter->getForces();
 90→          double *indices_max;
 91→          indices_max = new double[params.saddle_search_options.confine_positive
 92→                                       .bowl_active];
 93→
 94→          // determine the force for the x largest component
 95→          double f_max;
 96→          int i_max;
 97→          for (int j = 0;
 98→               j < params.saddle_search_options.confine_positive.bowl_active;
 99→               j++) {
100→            f_max = forceTemp.row(0).norm();
101→            i_max = 0;
102→            for (int i = 0; i < matter->numberOfAtoms(); i++) {
103→              if (f_max < forceTemp.row(i).norm()) {
104→                f_max = forceTemp.row(i).norm();
105→                i_max = i;
106→              }
107→            }
108→            forceTemp(3 * i_max + 0) = 0;
109→            forceTemp(3 * i_max + 1) = 0;
110→            forceTemp(3 * i_max + 2) = 0;
111→            indices_max[j] = i_max;
112→          }
113→          for (int i = 0; i < matter->numberOfAtoms(); i++) {
114→            forceTemp(3 * i + 0) = 0.0;
115→            forceTemp(3 * i + 1) = 0.0;
116→            forceTemp(3 * i + 2) = 0.0;
117→          }
118→          // only set the projected forces corresponding to the atoms subject to
119→          // the largest forces
120→          for (int j = 0;
121→               j < params.saddle_search_options.confine_positive.bowl_active;
122→               j++) {
123→            size_t tind = static_cast<size_t>(indices_max[j]);
124→            forceTemp(3 * tind + 0) = -proj(3 * tind + 0);
125→            forceTemp(3 * tind + 1) = -proj(3 * tind + 1);
126→            forceTemp(3 * tind + 2) = -proj(3 * tind + 2);
127→          }
128→          force = forceTemp;
129→          delete[] indices_max;
130→        } else {
131→          int sufficientForce = 0;
132→          double minForce =
133→              params.saddle_search_options.confine_positive.min_force;
134→          while (sufficientForce <
135→                 params.saddle_search_options.confine_positive.min_active) {
136→            sufficientForce = 0;
137→            force = matter->getForces();
138→            for (int i = 0; i < 3 * matter->numberOfAtoms(); i++) {
139→              if (fabs(force(i)) < minForce)
140→                force(i) = 0;
141→              else {
142→                sufficientForce = sufficientForce + 1;
143→                force(i) =
144→                    -params.saddle_search_options.confine_positive.boost *
145→                    proj(i);
146→              }
147→            }
148→            minForce *=
149→                params.saddle_search_options.confine_positive.scale_ratio;
150→          }
151→        }
152→      } else {
153→        // follow eigenmode
154→        force = -proj;
155→      }
156→    } else {
157→      // reversing force parallel to eigenmode
158→      force += -2. * proj;
159→    }
160→
161→    VectorXd forceV = VectorXd::Map(force.data(), 3 * matter->numberOfAtoms());
162→    return -forceV;
163→  }
164→  double getEnergy() { return matter->getPotentialEnergy(); }
165→  void setPositions(VectorXd x) { matter->setPositionsV(x); }
166→  VectorXd getPositions() { return matter->getPositionsV(); }
167→  int degreesOfFreedom() { return 3 * matter->numberOfAtoms(); }
168→  bool isConverged() {
169→    return getConvergence() < params.saddle_search_options.converged_force;
170→  }
171→
172→  double getConvergence() {
173→    if (params.optimizer_options.convergence_metric == "norm") {
174→      return matter->getForcesFreeV().norm();
175→    } else if (params.optimizer_options.convergence_metric == "max_atom") {
176→      return matter->maxForce();
177→    } else if (params.optimizer_options.convergence_metric == "max_component") {
178→      return matter->getForces().maxCoeff();
179→    } else {
180→      SPDLOG_DEBUG("[MinModeSaddleSearch] unknown opt_convergence_metric: {}",
181→                   params.optimizer_options.convergence_metric);
182→      std::exit(1);
183→    }
184→  }
185→
186→  VectorXd difference(VectorXd a, VectorXd b) { return matter->pbcV(a - b); }
187→};
