189→MinModeSaddleSearch::MinModeSaddleSearch(std::shared_ptr<Matter> matterPassed,
190→                                         AtomMatrix modePassed,
191→                                         double reactantEnergyPassed,
192→                                         const Parameters &parametersPassed,
193→                                         std::shared_ptr<Potential> potPassed)
194→    : SaddleSearchMethod(potPassed, parametersPassed),
195→      matter{matterPassed} {
196→  reactantEnergy = reactantEnergyPassed;
197→  mode = modePassed;
198→  status = STATUS_GOOD;
199→  iteration = 0;
200→  log = spdlog::get("combi");
201→
202→  if (params.saddle_search_options.minmode_method ==
203→      LowestEigenmode::MINMODE_DIMER) {
204→    if (params.dimer_options.improved) {
205→      minModeMethod = std::make_shared<ImprovedDimer>(matter, params, pot);
206→      if (true) { // TODO(rg): convert to param
207→        auto dimer = std::static_pointer_cast<ImprovedDimer>(minModeMethod);
208→
209→        // Convert the input AtomMatrix 'mode' to VectorXd
210→        VectorXd refVec =
211→            VectorXd::Map(mode.data(), 3 * matter->numberOfAtoms());
212→        refVec = refVec.array() * matter->getFreeV().array();
213→
214→        dimer->setReferenceMode(refVec);
215→      }
216→    } else {
217→      minModeMethod = std::make_shared<Dimer>(matter, params, pot);
218→    }
219→  } else if (params.saddle_search_options.minmode_method ==
220→             LowestEigenmode::MINMODE_LANCZOS) {
221→    minModeMethod = std::make_shared<Lanczos>(matter, params, pot);
222→  }
223→#ifdef WITH_GPRD
224→  else if (params.saddle_search_options.minmode_method ==
225→           LowestEigenmode::MINMODE_GPRDIMER) {
226→    minModeMethod = std::make_shared<AtomicGPDimer>(matter, params, pot);
227→  }
228→#endif
229→}
