231→int MinModeSaddleSearch::run() {
232→  SPDLOG_LOGGER_DEBUG(
233→      log, "Saddle point search started from reactant with energy {} eV.",
234→      reactantEnergy);
235→
236→  int optStatus;
237→  int firstIteration = 1;
238→  const char *forceLabel =
239→      params.optimizer_options.convergence_metric_label.c_str();
240→
241→  if (params.saddle_search_options.minmode_method ==
242→      LowestEigenmode::MINMODE_GPRDIMER) {
243→    SPDLOG_LOGGER_DEBUG(
244→        log, "================= Using the GP Dimer Library =================");
245→    minModeMethod->compute(matter, mode);
246→    if (minModeMethod->getEigenvalue() > 0) {
247→      printf("%f\n", minModeMethod->getEigenvalue());
248→      return STATUS_NONNEGATIVE_ABORT;
249→    }
250→    if (getEigenvalue() > 0.0 && status == STATUS_GOOD) {
251→      SPDLOG_LOGGER_DEBUG(log, "[MinModeSaddleSearch] eigenvalue not negative");
252→      status = STATUS_BAD_NO_NEGATIVE_MODE_AT_SADDLE;
253→    }
254→    if (fabs(minModeMethod->getEigenvalue()) <
255→        params.saddle_search_options.zero_mode_abort_curvature) {
256→      printf("%f\n", minModeMethod->getEigenvalue());
257→      status = STATUS_ZEROMODE_ABORT;
258→    }
259→    // These exist only for the gprdimer
260→    iteration = minModeMethod->totalIterations;
261→    forcecalls = minModeMethod->totalForceCalls;
262→  } else {
263→
264→    if (params.saddle_search_options.minmode_method ==
265→        LowestEigenmode::MINMODE_DIMER) {
266→      SPDLOG_LOGGER_INFO(log,
267→                         "[Dimer]  {:9s}   {:9s}   {:10s}   {:18s}   {:9s}   "
268→                         "{:7s}   {:6s}   {:4s}\n",
269→                         "Step", "Step Size", "Delta E", forceLabel,
270→                         "Curvature", "Torque", "Angle", "Rots", "Alignment");
271→    } else if (params.saddle_search_options.minmode_method ==
272→               LowestEigenmode::MINMODE_LANCZOS) {
273→      SPDLOG_LOGGER_INFO(
274→          log,
275→          "[Lanczos]  {:9s} {:9s} {:10s} {:18s} {:9s} {:10s} {:7s} {:5s}\n",
276→          "Step", "Step Size", "Delta E", forceLabel, "Curvature", "Rel Change",
277→          "Angle", "Iters");
278→    } else if (params.saddle_search_options.minmode_method ==
279→               LowestEigenmode::MINMODE_GPRDIMER) {
280→      SPDLOG_LOGGER_INFO(log,
281→                         "[GPRDimer]  {:9s}   {:9s}   {:10s}   {:18s}   {:9s}  "
282→                         " {:7s}   {:6s}   {:4s}\n",
283→                         "Step", "Step Size", "Delta E", forceLabel,
284→                         "Curvature", "Torque", "Angle", "Rots");
285→    }
286→
287→    ostringstream climb;
288→    climb << "climb";
289→    if (params.debug_options.write_movies) {
290→      matter->matter2con(climb.str(), false);
291→    }
292→
293→    AtomMatrix initialPosition = matter->getPositions();
294→
295→    auto objf = std::make_shared<MinModeObjectiveFunction>(
296→        matter, minModeMethod, mode, params);
297→    // objf->getGradient();
298→    if (params.saddle_search_options.nonnegative_displacement_abort) {
299→      objf->getGradient();
300→      if (minModeMethod->getEigenvalue() > 0) {
301→        printf("%f\n", minModeMethod->getEigenvalue());
302→        return STATUS_NONNEGATIVE_ABORT;
303→      }
304→    }
305→
306→    auto optim =
307→        helpers::create::mkOptim(objf, params.optimizer_options.method, params);
308→
309→    while (!objf->isConverged() || iteration == 0) {
310→
311→      if (!firstIteration) {
312→
313→        // Abort if negative mode becomes delocalized
314→        if (params.saddle_search_options.nonlocal_count_abort != 0) {
315→          long nm = numAtomsMoved(
316→              initialPosition - matter->getPositions(),
317→              params.saddle_search_options.nonlocal_distance_abort);
318→          if (nm >= params.saddle_search_options.nonlocal_count_abort) {
319→            status = STATUS_NONLOCAL_ABORT;
320→            break;
321→          }
322→        }
323→
324→        // Abort if negative mode becomes zero
325→        // cout << "curvature: "<<fabs(minModeMethod->getEigenvalue())<<"\n";
326→        if (fabs(minModeMethod->getEigenvalue()) <
327→            params.saddle_search_options.zero_mode_abort_curvature) {
328→          printf("%f\n", minModeMethod->getEigenvalue());
329→          status = STATUS_ZEROMODE_ABORT;
330→          break;
331→        }
332→      }
333→      firstIteration = 0;
334→
335→      if (iteration >= params.saddle_search_options.max_iterations) {
336→        status = STATUS_BAD_MAX_ITERATIONS;
337→        break;
338→      }
339→
340→      AtomMatrix pos = matter->getPositions();
341→
342→      try {
343→        if (params.saddle_search_options.confine_positive.bowl_breakout) {
344→          // use negative step to communicate that the system is the negative
345→          // region and a max step should be performed
346→          if ((minModeMethod->getEigenvalue() > 0) and
347→              (params.optimizer_options.method == OptType::CG)) {
348→            optStatus = optim->step(-params.optimizer_options.max_move);
349→          } else {
350→            optStatus = optim->step(params.optimizer_options.max_move);
351→          }
352→        } else {
353→          optStatus = optim->step(params.optimizer_options.max_move);
354→        }
355→      } catch (const eonc::DimerModeRestoredException &e) {
356→        // Dimer lost mode but restored to valid negative curvature state
357→        // Check if we're now converged
358→        SPDLOG_LOGGER_DEBUG(
359→            log, "Dimer restored to best state.  Checking convergence...");
360→
361→        // Force might have changed - recompute convergence
362→        if (objf->isConverged()) {
363→          SPDLOG_LOGGER_DEBUG(log, "Converged after dimer restoration.");
364→          status = STATUS_GOOD;
365→        } else {
366→          // Not converged, but we have a valid state - report as partial
367→          // success
368→          status = STATUS_DIMER_RESTORED_BEST;
369→        }
370→        break;
371→      } catch (const eonc::DimerModeLostException &e) {
372→        // Truly lost the mode with no valid state
373→        SPDLOG_LOGGER_WARN(log, "Dimer lost mode completely. Aborting.");
374→        status = STATUS_DIMER_LOST_MODE;
375→        break;
376→      }
377→
378→      if (optStatus < 0) {
379→        status = STATUS_OPTIMIZER_ERROR;
380→        break;
381→      }
382→
383→      double de = objf->getEnergy() - reactantEnergy;
384→      // should be the total displacement of the system not just a single atom
385→      // double stepSize =
386→      // helper_functions::maxAtomMotion(matter->pbc(matter->getPositions() -
387→      // pos));
388→
389→      double stepSize;
390→
391→      // Melander, Laasonen, Jonsson, JCTC, 11(3), 1055–1062, 2015
392→      // http://doi.org/10.1021/ct501155k
393→      if (params.saddle_search_options.remove_rotation) {
394→        rotationRemove(pos, matter);
395→      }
396→      stepSize = (matter->pbc(matter->getPositions() - pos)).norm();
397→
398→      iteration++;
399→
400→      if (params.saddle_search_options.minmode_method ==
401→          LowestEigenmode::MINMODE_DIMER) {
402→        SPDLOG_LOGGER_DEBUG(
403→            log,
404→            "[Dimer]  {:9}   {:9.7f}   {:10.4f}   {:18.5e}   {:9.4f}   {:7.3f} "
405→            "  {:6.3f}   {:4}\n",
406→            iteration, stepSize, matter->getPotentialEnergy() - reactantEnergy,
407→            objf->getConvergence(), minModeMethod->getEigenvalue(),
408→            minModeMethod->statsTorque, minModeMethod->statsAngle,
409→            minModeMethod->statsRotations);
410→      } else if (params.saddle_search_options.minmode_method ==
411→                 LowestEigenmode::MINMODE_LANCZOS) {
412→        SPDLOG_LOGGER_DEBUG(
413→            log,
414→            "[Lanczos]  {:9} {:9.6f} {:10.4f} {:18.5e} {:9.4f} {:10.6f} "
415→            "{:7.3f} {:5}\n",
416→            iteration, stepSize, matter->getPotentialEnergy() - reactantEnergy,
417→            objf->getConvergence(), minModeMethod->getEigenvalue(),
418→            minModeMethod->statsTorque, minModeMethod->statsAngle,
419→            minModeMethod->statsRotations);
420→      } else if (params.saddle_search_options.minmode_method ==
421→                 LowestEigenmode::MINMODE_GPRDIMER) {
422→        SPDLOG_LOGGER_DEBUG(
423→            log,
424→            "[Dimer]  {:9}   {:9.7f}   {:10.4f}   {:18.5e}   {:9.4f}   {:7.3f} "
425→            "  {:6.3f}   {:4}\n",
426→            iteration, stepSize, matter->getPotentialEnergy() - reactantEnergy,
427→            objf->getConvergence(), minModeMethod->getEigenvalue(),
428→            minModeMethod->statsTorque, minModeMethod->statsAngle,
429→            minModeMethod->statsRotations);
430→      } else {
431→        log = spdlog::get("_traceback");
432→        SPDLOG_LOGGER_CRITICAL(
433→            log, "[MinModeSaddleSearch] Unknown min_mode_method: {}",
434→            params.saddle_search_options.minmode_method);
435→        std::exit(1);
436→      }
437→
438→      if (params.debug_options.write_movies) {
439→        matter->matter2con(climb.str(), true);
440→      }
441→
442→      if (params.main_options.checkpoint) {
443→        matter->matter2con("displacement_cp.con", false);
444→        FILE *fileMode = fopen("mode_cp.dat", "wb");
445→        helper_functions::saveMode(fileMode, matter,
446→                                   minModeMethod->getEigenvector());
447→        fclose(fileMode);
448→      }
449→
450→      if (de > params.saddle_search_options.max_energy) {
451→        status = STATUS_BAD_HIGH_ENERGY;
452→        break;
453→      }
454→
455→      if (params.saddle_search_options.minmode_method ==
456→          LowestEigenmode::MINMODE_DIMER) {
457→        // We need to cast the pointer to access the ImprovedDimer-specific flag
458→        auto dimer = std::dynamic_pointer_cast<ImprovedDimer>(minModeMethod);
459→
460→        if (dimer && !dimer->rotationDidConverge) {
461→          // This shouldn't happen if we caught the exceptions above,
462→          // but keep as safety check
463→          if (dimer->getEigenvalue() < 0.0) {
464→            SPDLOG_LOGGER_DEBUG(log,
465→                                "Dimer restored to valid state.  C_tau={:.4f}",
466→                                dimer->getEigenvalue());
467→            status = STATUS_DIMER_RESTORED_BEST;
468→          } else {
469→            status = STATUS_DIMER_LOST_MODE;
470→          }
471→          break;
472→        }
473→      }
474→    }
475→
476→    if (iteration == 0)
477→      minModeMethod->compute(matter, mode);
478→
479→    if (getEigenvalue() > 0.0 && status == STATUS_GOOD) {
480→      SPDLOG_LOGGER_DEBUG(log, "[MinModeSaddleSearch] eigenvalue not negative");
481→      status = STATUS_BAD_NO_NEGATIVE_MODE_AT_SADDLE;
482→    }
483→  }
484→
485→  return status;
486→}
