 22→int DynamicsSaddleSearch::run(void) {
 23→  std::vector<std::shared_ptr<Matter>> MDSnapshots;
 24→  std::vector<double> MDTimes;
 25→  SPDLOG_LOGGER_DEBUG(log, "Starting dynamics NEB saddle search");
 26→
 27→  ifstream massFile("masses.dat");
 28→  if (massFile.is_open()) {
 29→    SPDLOG_LOGGER_DEBUG(log, "Found mass weights file");
 30→    massFile.close();
 31→    Eigen::VectorXd masses =
 32→        helper_functions::loadMasses("masses.dat", saddle->numberOfAtoms());
 33→    saddle->setMasses(masses);
 34→    SPDLOG_LOGGER_DEBUG(log, "Applied mass weights");
 35→  } else {
 36→    SPDLOG_LOGGER_DEBUG(log, "No mass weights file found");
 37→    massFile.close();
 38→  }
 39→
 40→  Dynamics dyn(saddle.get(), params);
 41→  SPDLOG_LOGGER_DEBUG(
 42→      log, "Initializing velocities from Maxwell-Boltzmann distribution");
 43→  dyn.setTemperature(params.saddle_search_options.dynamics.temperature);
 44→  dyn.setThermalVelocity();
 45→
 46→  int dephaseSteps = int(floor(params.parallel_replica_options.dephase_time /
 47→                                   params.dynamics_options.time_step +
 48→                               0.5));
 49→
 50→  while (true) {
 51→
 52→    SPDLOG_LOGGER_DEBUG(log, "Dephasing: {} steps", dephaseSteps);
 53→    // always start from the initial configuration
 54→    *saddle = *reactant;
 55→    dyn.setThermalVelocity();
 56→
 57→    // Dephase MD trajectory
 58→    for (int step = 1; step <= dephaseSteps; step++) {
 59→      dyn.oneStep(step);
 60→    }
 61→
 62→    // Check to see if a transition occured
 63→    Matter min(pot, params);
 64→    min = *saddle;
 65→    min.relax();
 66→
 67→    if (min.compare(*reactant)) {
 68→      SPDLOG_LOGGER_DEBUG(log, "Dephasing successful");
 69→      break;
 70→    } else {
 71→      SPDLOG_LOGGER_DEBUG(log,
 72→                          "Transition occured during dephasing; Restarting");
 73→      dephaseSteps /= 2;
 74→      if (dephaseSteps < 1)
 75→        dephaseSteps = 1;
 76→    }
 77→  }
 78→
 79→  BondBoost bondBoost(saddle.get(), params);
 80→  if (params.hyperdynamics_options.bias_potential ==
 81→      Hyperdynamics::BOND_BOOST) {
 82→    SPDLOG_LOGGER_DEBUG(log, "Initializing Bond Boost");
 83→    bondBoost.initialize();
 84→  }
 85→
 86→  int checkInterval =
 87→      int(params.saddle_search_options.dynamics.state_check_interval /
 88→              params.dynamics_options.time_step +
 89→          0.5);
 90→  int recordInterval =
 91→      int(params.saddle_search_options.dynamics.record_interval /
 92→              params.dynamics_options.time_step +
 93→          0.5);
 94→
 95→  if (params.debug_options.write_movies == true) {
 96→    saddle->matter2con("dynamics", false);
 97→  }
 98→
 99→  for (int step = 1; step <= params.dynamics_options.steps; step++) {
100→    dyn.oneStep(step);
101→
102→    if (step % recordInterval == 0 && recordInterval != 0) {
103→      SPDLOG_LOGGER_DEBUG(
104→          log, "recording configuration at step {} time {:.3f}", step,
105→          step * params.dynamics_options.time_step * params.constants.timeUnit);
106→      auto tmp = std::shared_ptr<Matter>(saddle);
107→      *tmp = *saddle;
108→      MDSnapshots.push_back(tmp);
109→      MDTimes.push_back(step * params.dynamics_options.time_step);
110→    }
111→
112→    if (params.debug_options.write_movies == true) {
113→      saddle->matter2con("dynamics", true);
114→    }
115→
116→    if (step % checkInterval == 0) {
117→      SPDLOG_LOGGER_DEBUG(log, "Minimizing trajectory, step {}", step);
118→
119→      product = saddle;
120→      product->relax(false, false);
121→
122→      if (!product->compare(*reactant)) {
123→        // SPDLOG_LOGGER_DEBUG(log, "Force calls total: %i",
124→        // Potential::fcallsTotal);
125→        SPDLOG_LOGGER_DEBUG(log, "Found new state");
126→        int image = refineTransition(MDSnapshots, product);
127→        *saddle = *MDSnapshots[image];
128→        SPDLOG_LOGGER_DEBUG(log, "Found transition at snapshot image {}",
129→                            image);
130→        for (int ii = 0; ii < (int)MDTimes.size(); ii++)
131→          SPDLOG_LOGGER_DEBUG(log, "MDTimes[{}] = {:.3f}", ii,
132→                              MDTimes[ii] * params.constants.timeUnit);
133→        // subtract off half the record interval in order to not introduce a
134→        // systematic bias towards longer times.
135→        time = MDTimes[image] -
136→               params.saddle_search_options.dynamics.record_interval / 2.0;
137→        SPDLOG_LOGGER_DEBUG(log, "Transition time {:.2f} fs",
138→                            time * params.constants.timeUnit);
139→
140→        NudgedElasticBand neb(reactant, product, params, pot);
141→
142→        if (params.saddle_search_options.dynamics.linear_interpolation ==
143→            false) {
144→          SPDLOG_LOGGER_DEBUG(
145→              log, "Interpolating initial band through MD transition state");
146→          AtomMatrix reactantToSaddle =
147→              saddle->pbc(saddle->getPositions() - reactant->getPositions());
148→          AtomMatrix saddleToProduct =
149→              saddle->pbc(product->getPositions() - saddle->getPositions());
150→          SPDLOG_LOGGER_DEBUG(log,
151→                              "Initial band saved to neb_initial_band.con");
152→          neb.path[0]->matter2con("neb_initial_band.con", false);
153→          for (int image = 1; image <= neb.numImages; image++) {
154→            int mid = neb.numImages / 2 + 1;
155→            if (image < mid) {
156→              double frac = ((double)image) / ((double)mid);
157→              neb.path[image]->setPositions(reactant->getPositions() +
158→                                            frac * reactantToSaddle);
159→            } else if (image > mid) {
160→              double frac =
161→                  (double)(image - mid) / (double)(neb.numImages - mid + 1);
162→              neb.path[image]->setPositions(saddle->getPositions() +
163→                                            frac * saddleToProduct);
164→            } else if (image == mid) {
165→              neb.path[image]->setPositions(saddle->getPositions());
166→            }
167→            neb.path[image]->matter2con("neb_initial_band.con", true);
168→          }
169→          neb.path[neb.numImages + 1]->matter2con("neb_initial_band.con", true);
170→        } else {
171→          SPDLOG_LOGGER_DEBUG(
172→              log, "Linear interpolation between minima used for initial band");
173→          neb.path[0]->matter2con("neb_initial_band.con", false);
174→          for (int j = 1; j <= neb.numImages + 1; j++) {
175→            neb.path[j]->matter2con("neb_initial_band.con", true);
176→          }
177→        }
178→
179→        AtomMatrix mode;
180→        if (params.neb_options.max_iterations > 0) {
181→          LowestEigenmode *minModeMethod;
182→          if (params.saddle_search_options.minmode_method ==
183→              LowestEigenmode::MINMODE_DIMER) {
184→            if (params.dimer_options.improved) {
185→              minModeMethod = new ImprovedDimer(saddle, params, pot);
186→            } else {
187→              minModeMethod = new Dimer(saddle, params, pot);
188→            }
189→          } else if (params.saddle_search_options.minmode_method ==
190→                     LowestEigenmode::MINMODE_LANCZOS) {
191→            minModeMethod = new Lanczos(saddle, params, pot);
192→          }
193→
194→          neb.compute();
195→          neb.printImageData(true);
196→          int extremumImage = -1;
197→          int j;
198→          for (j = 0; j < neb.numExtrema; j++) {
199→            //                        if (neb.extremumCurvature[j] < 0.0) {
200→            if (neb.extremumCurvature[j] <
201→                params.saddle_search_options.dynamics.max_init_curvature) {
202→              extremumImage = (int)floor(neb.extremumPosition[j]);
203→              *saddle = *neb.path[extremumImage];
204→              double interpDistance =
205→                  neb.extremumPosition[j] - (double)extremumImage;
206→              AtomMatrix bandDirection =
207→                  saddle->pbc(neb.path[extremumImage + 1]->getPositions() -
208→                              neb.path[extremumImage]->getPositions());
209→              saddle->setPositions(interpDistance * bandDirection +
210→                                   saddle->getPositions());
211→              mode = saddle->pbc(neb.path[extremumImage + 1]->getPositions() -
212→                                 saddle->getPositions());
213→              mode.normalize();
214→              minModeMethod->compute(saddle, mode);
215→              double eigenvalue = minModeMethod->getEigenvalue();
216→              SPDLOG_LOGGER_DEBUG(log, "extrema #%i has eigenvalue %.8f", j + 1,
217→                                  eigenvalue);
218→
219→              if (eigenvalue < 0) {
220→                SPDLOG_LOGGER_DEBUG(
221→                    log, "chose image %i (extrema #%i) as extremum image",
222→                    extremumImage, j + 1);
223→                break;
224→              } else {
225→                extremumImage = -1;
226→              }
227→            }
228→          }
229→
230→          delete minModeMethod;
231→
232→          if (extremumImage != -1) {
233→            *saddle = *neb.path[extremumImage];
234→            double interpDistance =
235→                neb.extremumPosition[j] - (double)extremumImage;
236→            SPDLOG_LOGGER_DEBUG(log, "interpDistance %f", interpDistance);
237→            AtomMatrix bandDirection =
238→                saddle->pbc(neb.path[extremumImage + 1]->getPositions() -
239→                            neb.path[extremumImage]->getPositions());
240→            saddle->setPositions(interpDistance * bandDirection +
241→                                 saddle->getPositions());
242→            mode = saddle->pbc(neb.path[extremumImage + 1]->getPositions() -
243→                               saddle->getPositions());
244→            mode.normalize();
245→          } else {
246→            SPDLOG_LOGGER_DEBUG(
247→                log, "no maxima found, using max energy non-endpoint image");
248→            double maxEnergy = -INFINITY;
249→            for (int image = 1; image <= neb.numImages; image++) {
250→              double U = neb.path[image]->getPotentialEnergy();
251→              if (U > maxEnergy) {
252→                maxEnergy = U;
253→                *saddle = *neb.path[image];
254→                mode = saddle->pbc(neb.path[image + 1]->getPositions() -
255→                                   saddle->getPositions());
256→                mode.normalize();
257→              }
258→            }
259→            if (maxEnergy <= reactant->getPotentialEnergy()) {
260→              SPDLOG_LOGGER_DEBUG(log, "warning: no barrier found");
261→              return MinModeSaddleSearch::STATUS_BAD_NO_BARRIER;
262→            }
263→          }
264→        } else {
265→          neb.maxEnergyImage = neb.numImages / 2 + 1;
266→        }
267→
268→        SPDLOG_LOGGER_DEBUG(
269→            log, "Initial saddle guess saved to saddle_initial_guess.con");
270→        saddle->matter2con("saddle_initial_guess.con");
271→        MinModeSaddleSearch search = MinModeSaddleSearch(
272→            saddle, mode, reactant->getPotentialEnergy(), params, pot);
273→        int minModeStatus = search.run();
274→
275→        if (minModeStatus != MinModeSaddleSearch::STATUS_GOOD) {
276→          SPDLOG_LOGGER_DEBUG(log, "error in min mode saddle search");
277→          return minModeStatus;
278→        }
279→
280→        eigenvalue = search.getEigenvalue();
281→        eigenvector = search.getEigenvector();
282→        SPDLOG_LOGGER_DEBUG(log, "eigenvalue: {:.3f}", eigenvalue);
283→
284→        double barrier =
285→            saddle->getPotentialEnergy() - reactant->getPotentialEnergy();
286→        SPDLOG_LOGGER_DEBUG(log, "found barrier of {:.3f}", barrier);
287→        MDSnapshots.clear();
288→        MDTimes.clear();
289→        // SPDLOG_LOGGER_DEBUG(log, "Force calls total: %i",
290→        // Potential::fcallsTotal);
291→        return MinModeSaddleSearch::STATUS_GOOD;
292→      } else {
293→        SPDLOG_LOGGER_DEBUG(log, "Still in original state");
294→        MDTimes.clear();
295→        MDSnapshots.clear();
296→      }
297→    }
298→  }
299→
300→  MDSnapshots.clear();
301→  time = params.dynamics_options.steps * params.dynamics_options.time_step;
302→  return MinModeSaddleSearch::STATUS_BAD_MD_TRAJECTORY_TOO_SHORT;
303→}
304→
305→int DynamicsSaddleSearch::refineTransition(
306→    std::vector<std::shared_ptr<Matter>> MDSnapshots,
307→    std::shared_ptr<Matter> product) {
308→  int min, max, mid;
309→  bool midTest;
310→  min = 0;
311→  max = MDSnapshots.size() - 1;
312→  if (max == 0) {
313→    return 0;
314→  }
315→
316→  SPDLOG_LOGGER_DEBUG(log, "refining transition time");
317→
318→  while ((max - min) > 1) {
319→    mid = min + (max - min) / 2;
320→    SPDLOG_LOGGER_DEBUG(log, "minimizing image {}", mid);
321→    Matter snapshot(pot, params);
322→    snapshot = *MDSnapshots[mid];
323→
324→    snapshot.relax(false);
325→
326→    midTest = snapshot.compare(*reactant);
327→
328→    if (midTest) {
329→      SPDLOG_LOGGER_DEBUG(log, "image {} minimizes to reactant", mid);
330→      min = mid;
331→    } else {
332→      SPDLOG_LOGGER_DEBUG(log, "image {} minimizes to product", mid);
333→      *product = snapshot;
334→      max = mid;
335→    }
336→  }
337→
338→  return (min + max) / 2;
339→}
