21→int BasinHoppingSaddleSearch::run(void) {
22→  // minimize "saddle"
23→  saddle->relax(false, true, false, "displacementmin");
24→  product = std::make_shared<Matter>(pot, params);
25→  *product = *saddle;
26→  // accept or reject based on boltzman
27→  // exp(-de/(kB*params.main_options.temperature))
28→  double eproduct, ereactant, de;
29→  eproduct = product->getPotentialEnergy();
30→  ereactant = reactant->getPotentialEnergy();
31→  de = eproduct - ereactant;
32→  double kB = params.constants.kB;
33→  double Temperature = params.main_options.temperature;
34→  double arg = -de / (kB * Temperature);
35→  double p = exp(arg);
36→  double r = helper_functions::random();
37→  if (ereactant < eproduct) {
38→    if (r > p) { // reject
39→      return 1;
40→    }
41→  }
42→  // NEB reactant to minimized "saddle"
43→  NudgedElasticBand neb(reactant, product, params, pot);
44→  neb.path[0]->matter2con("neb_initial_band.con", false);
45→  for (int j = 1; j < neb.numImages; j++) {
46→    neb.path[j]->matter2con("neb_initial_band", true);
47→  }
48→  neb.compute();
49→  // pick the maximum energy image along the band
50→  double Emax = -1e100;
51→  int HighestImage = 0;
52→
53→  for (int i = 1; i < neb.numImages; i++) {
54→    double Etest = neb.path[i]->getPotentialEnergy();
55→    SPDLOG_LOGGER_DEBUG(log, "i: {} Etest: {:.f}", i, Etest);
56→    if (Etest > Emax) {
57→      Emax = Etest;
58→      HighestImage = i;
59→    }
60→  }
61→  // do dimer
62→  // Calculate initial direction
63→  AtomMatrix r_1 = neb.path[HighestImage - 1]->getPositions();
64→  AtomMatrix r_2 = neb.path[HighestImage]->getPositions();
65→  AtomMatrix r_3 = neb.path[HighestImage + 1]->getPositions();
66→  AtomMatrix direction = (r_3 - r_1) / 2;
67→  MinModeSaddleSearch dim(neb.path[HighestImage], direction.normalized(),
68→                          ereactant, params, pot);
69→  dim.run();
70→  *saddle = *neb.path[HighestImage];
71→  eigenvalue = dim.getEigenvalue();
72→  eigenvector = dim.getEigenvector();
73→  return 0;
74→}
