 22→long EpiCenters::cnaEpiCenter(const Matter *matter, double neighborCutoff) {
 23→  long *cnaList;
 24→  long j, nAtoms, indexEpiCenter;
 25→  double tempDouble;
 26→  nAtoms = matter->numberOfAtoms();
 27→  cnaList = new long[nAtoms];
 28→  indexEpiCenter = -2; // initialize to a value that will fail the assert if no
 29→                       // EpiCenter is found
 30→  //----- Initialize end -----
 31→  // std::cout<<"cnaEpiCenter\n";
 32→
 33→  cna(cnaList, matter, neighborCutoff);
 34→
 35→  // count atoms that are not FCC or HCP and are free to move
 36→  j = 0;
 37→  for (int i = 0; i < nAtoms; i++) {
 38→    if ((cnaList[i] == 2) && !(matter->getFixed(i)))
 39→      j++;
 40→  }
 41→  // pick a random atom being both free and not FCC or HCP coordinated
 42→  tempDouble = randomDouble(j);
 43→  j = (long)tempDouble + 1;
 44→  for (int i = 0; i < nAtoms; i++) {
 45→    if ((cnaList[i] == 2) && !(matter->getFixed(i))) {
 46→      j--;
 47→      if (!j) {
 48→        indexEpiCenter = i;
 49→        break;
 50→      }
 51→    }
 52→  }
 53→  delete[] cnaList;
 54→
 55→  // make certain the chosen atom index is within the domain of the atom list
 56→  assert(indexEpiCenter > -1 && indexEpiCenter < nAtoms);
 57→  return (indexEpiCenter);
 58→}
