149→void EpiCenters::cna(long *cna, const Matter *matter, double neighborCutoff) {
150→  int a1 = 0;
151→  int a2 = 0;
152→  int a3 = 0;
153→  int nAtoms;
154→  int unsigned n = 0;
155→  int unsigned n1 = 0;
156→  int unsigned n2 = 0;
157→  int unsigned m2 = 0;
158→  int j1 = 0;
159→  int j2 = 0;
160→  double diffR;
161→  int nBonds = 0;
162→  int bondsSum = 0;
163→  nAtoms = (int)matter->numberOfAtoms();
164→  vector<int> nFCC(nAtoms);
165→  vector<int> nHCP(nAtoms);
166→  vector<vector<int>> neighborLists(nAtoms);
167→  //----- Initialize end -----
168→  // std::cout<<"cna\n";
169→
170→  for (int i = 0; i < nAtoms - 1; i++) {
171→    for (int j = i + 1; j < nAtoms; j++) {
172→      diffR = matter->distance(i, j);
173→      if (diffR < neighborCutoff) {
174→        neighborLists[i].push_back(j);
175→        neighborLists[j].push_back(i);
176→      }
177→    }
178→  }
179→  for (a2 = 0; a2 < nAtoms; a2++) {
180→    vector<int> &nbs2 = neighborLists[a2];
181→    for (n2 = 0; n2 < nbs2.size(); n2++) {
182→      a1 = nbs2[n2];
183→      if (a1 < a2) {
184→        vector<int> common;
185→        vector<int> &nbs1 = neighborLists[a1];
186→        for (n1 = 0; n1 < nbs1.size(); n1++) {
187→          a3 = nbs1[n1];
188→          for (m2 = 0; m2 < nbs2.size(); m2++)
189→            if (a3 == nbs2[m2])
190→              common.push_back(a3);
191→        }
192→        if (common.size() == 4) {
193→          nBonds = 0;
194→          bondsSum = 0;
195→          for (j2 = 1; j2 < 4; j2++) {
196→            vector<int> &nbs = neighborLists[common[j2]];
197→            for (j1 = 0; j1 < j2; j1++) {
198→              for (n = 0; n < nbs.size(); n++) {
199→                if (common[j1] == nbs[n]) {
200→                  nBonds++;
201→                  bondsSum += j1 + j2;
202→                  break;
203→                }
204→              }
205→            }
206→          }
207→          if (nBonds == 2) {
208→            if (bondsSum == 6) {
209→              nFCC[a1]++;
210→              nFCC[a2]++;
211→            } else {
212→              nHCP[a1]++;
213→              nHCP[a2]++;
214→            }
215→          }
216→        }
217→      }
218→    }
219→  }
220→  // 0: fcc (421), 1: hcp (422), 2: other
221→  for (int i = 0; i < nAtoms; i++) {
222→    if (neighborLists[i].size() == 12) {
223→      if (nFCC[i] == 12)
224→        cna[i] = 0;
225→      else if (nFCC[i] == 6 && nHCP[i] == 6)
226→        cna[i] = 1;
227→      else
228→        cna[i] = 2;
229→    } else
230→      cna[i] = 2;
231→  }
232→  return;
233→}
