235→void EpiCenters::coordination(long *coordinationVal, const Matter *matter,
236→                              double neighborCutoff) {
237→  long nAtoms;
238→  double diffR;
239→  nAtoms = matter->numberOfAtoms();
240→  for (int i = 0; i < nAtoms; i++)
241→    coordinationVal[i] = 0;
242→  //----- Initialize end -----
243→  // std::cout<<"coordination\n";
244→
245→  for (int i = 0; i < nAtoms - 1; i++) {
246→    for (int j = i + 1; j < nAtoms; j++) {
247→      // determine coordination number
248→      diffR = matter->distance(i, j);
249→      if (diffR < neighborCutoff) {
250→        coordinationVal[i] = coordinationVal[i] + 1;
251→        coordinationVal[j] = coordinationVal[j] + 1;
252→      }
253→    }
254→  }
255→  return;
256→}
