258→void EpiCenters::coordinationLessOrEqual(bool *result, long coordinationMaxVal,
259→                                         const Matter *matter,
260→                                         double neighborCutoff) {
261→  long *coordinationVal;
262→  long nAtoms;
263→  nAtoms = matter->numberOfAtoms();
264→  coordinationVal = new long[nAtoms];
265→  //----- Initialize end -----
266→  // std::cout<<"coordinationLessOrEqual\n";
267→
268→  coordination(coordinationVal, matter, neighborCutoff);
269→
270→  for (int i = 0; i < nAtoms; i++) {
271→    if ((coordinationVal[i] < coordinationMaxVal + 1) && !(matter->getFixed(i)))
272→      result[i] = true;
273→    else
274→      result[i] = false;
275→  }
276→  delete[] coordinationVal;
277→
278→  return;
279→}
