281→long EpiCenters::minCoordination(const Matter *matter, double neighborCutoff) {
282→  long *coordinationVal;
283→  long nAtoms;
284→  long minCoordinationVal;
285→  nAtoms = matter->numberOfAtoms();
286→  coordinationVal = new long[nAtoms];
287→  //----- Initialize end -----
288→  // std::cout<<"minCoordination\n";
289→
290→  coordination(coordinationVal, matter, neighborCutoff);
291→  // LONG_MAX is a the maximal value a long can achieve, from library limits
292→  minCoordinationVal = LONG_MAX;
293→
294→  for (int i = 0; i < nAtoms; i++) {
295→    if ((coordinationVal[i] < minCoordinationVal) && !(matter->getFixed(i))) {
296→      minCoordinationVal = coordinationVal[i];
297→    }
298→  }
299→  delete[] coordinationVal;
300→
301→  return (minCoordinationVal);
302→}
