 477→int Parameters::load(string filename) {
 478→  FILE *fh;
 479→
 480→  fh = fopen(filename.c_str(), "rb");
 481→  if (fh == NULL) {
 482→    fprintf(stderr, "error: %s\n", strerror(errno));
 483→    return 1;
 484→  }
 485→  int error = load(fh);
 486→  fclose(fh);
 487→  return error;
 488→}
