 490→int Parameters::load(FILE *file) {
 491→
 492→  CIniFile ini;
 493→  ini.CaseInsensitive();
 494→  int error = 0;
 495→
 496→  if (ini.ReadFile(file)) {
 497→
 498→    // [Main] //
 499→
 500→    main_options.job =
 501→        magic_enum::enum_cast<JobType>(ini.GetValue("Main", "job"),
 502→                                       magic_enum::case_insensitive)
 503→            .value_or(JobType::Unknown);
 504→    main_options.temperature =
 505→        ini.GetValueF("Main", "temperature", main_options.temperature);
 506→    main_options.randomSeed =
 507→        ini.GetValueL("Main", "random_seed", main_options.randomSeed);
 508→    main_options.checkpoint =
 509→        ini.GetValueB("Main", "checkpoint", main_options.checkpoint);
 510→    main_options.quiet = ini.GetValueB("Main", "quiet", main_options.quiet);
 511→    main_options.writeLog =
 512→        ini.GetValueB("Main", "write_log", main_options.writeLog);
 513→    main_options.finiteDifference = ini.GetValueF(
 514→        "Main", "finite_difference", main_options.finiteDifference);
 515→    // Initialize random generator
 516→    if (main_options.randomSeed < 0) {
 517→      unsigned i = time(NULL);
 518→      main_options.randomSeed = i;
 519→      helper_functions::random(i);
 520→    } else {
 521→      helper_functions::random(main_options.randomSeed);
 522→    }
 523→    main_options.maxForceCalls =
 524→        ini.GetValueL("Main", "max_force_calls", main_options.maxForceCalls);
 525→    main_options.removeNetForce =
 526→        ini.GetValueB("Main", "remove_net_force", main_options.removeNetForce);
 527→
 528→    // [Potential] //
 529→
 530→    potential_options.potential =
 531→        magic_enum::enum_cast<PotType>(ini.GetValue("Potential", "potential"),
 532→                                       magic_enum::case_insensitive)
 533→            .value_or(PotType::UNKNOWN);
 534→    potential_options.MPIPollPeriod = ini.GetValueF(
 535→        "Potential", "mpi_poll_period", potential_options.MPIPollPeriod);
 536→    potential_options.LAMMPSLogging = ini.GetValueB(
 537→        "Potential", "lammps_logging", potential_options.LAMMPSLogging);
 538→    potential_options.LAMMPSThreads = (int)ini.GetValueL(
 539→        "Potential", "lammps_threads", potential_options.LAMMPSThreads);
 540→    potential_options.EMTRasmussen = ini.GetValueB(
 541→        "Potential", "emt_rasmussen", potential_options.EMTRasmussen);
 542→    potential_options.extPotPath =
 543→        ini.GetValue("Potential", "ext_pot_path", potential_options.extPotPath);
 544→
 545→    if (potential_options.potential == PotType::MPI ||
 546→        potential_options.potential == PotType::VASP ||
 547→        potential_options.potential == PotType::BOPFOX ||
 548→        potential_options.potential == PotType::BOP) {
 549→      potential_options.LogPotential = true;
 550→    } else {
 551→      potential_options.LogPotential = false;
 552→    }
 553→    potential_options.LogPotential = ini.GetValueB(
 554→        "Potential", "log_potential", potential_options.LogPotential);
 555→
 556→    // [AMS]
 557→    if (potential_options.potential == PotType::AMS) {
 558→      ams_options.engine = ini.GetValue("AMS", "engine", ams_options.engine);
 559→      ams_options.forcefield =
 560→          ini.GetValue("AMS", "forcefield", ams_options.forcefield);
 561→      ams_options.resources =
 562→          ini.GetValue("AMS", "resources", ams_options.resources);
 563→      ams_options.model = ini.GetValue("AMS", "model", ams_options.model);
 564→      ams_options.xc = ini.GetValue("AMS", "xc", ams_options.xc);
 565→      ams_options.basis = ini.GetValue("AMS", "basis", ams_options.basis);
 566→    }
 567→    // [AMS_IO]
 568→    if (potential_options.potential == PotType::AMS_IO) {
 569→      ams_options.engine = ini.GetValue("AMS_IO", "engine", ams_options.engine);
 570→      ams_options.forcefield =
 571→          ini.GetValue("AMS_IO", "forcefield", ams_options.forcefield);
 572→      ams_options.model = ini.GetValue("AMS_IO", "model", ams_options.model);
 573→      ams_options.xc = ini.GetValue("AMS_IO", "xc", ams_options.xc);
 574→    }
 575→    // [AMS_ENV]
 576→    // This is only needed if the regular calls do not work
 577→    // e.g. on a MacOS machine
 578→    if (potential_options.potential == PotType::AMS_IO ||
 579→        potential_options.potential == PotType::AMS) {
 580→      ams_options.env.amshome =
 581→          ini.GetValue("AMS_ENV", "amshome", ams_options.env.amshome);
 582→      ams_options.env.scm_tmpdir =
 583→          ini.GetValue("AMS_ENV", "scm_tmpdir", ams_options.env.scm_tmpdir);
 584→      ams_options.env.scmlicense =
