 589→          ini.GetValue("AMS_ENV", "amsbin", ams_options.env.amsbin);
 590→      ams_options.env.amsresources =
 591→          ini.GetValue("AMS_ENV", "amsresources", ams_options.env.amsresources);
 592→    }
 593→    // [XTBPot]
 594→    if (potential_options.potential == PotType::XTB) {
 595→      xtb_options.paramset =
 596→          ini.GetValue("XTBPot", "paramset", xtb_options.paramset);
 597→      xtb_options.acc = ini.GetValueF("XTBPot", "accuracy", xtb_options.acc);
 598→      xtb_options.elec_temperature = ini.GetValueF(
 599→          "XTBPot", "electronic_temperature", xtb_options.elec_temperature);
 600→      xtb_options.maxiter =
 601→          ini.GetValueL("XTBPot", "max_iterations", xtb_options.maxiter);
 602→      xtb_options.uhf = ini.GetValueL("XTBPot", "uhf", xtb_options.uhf);
 603→      xtb_options.charge =
 604→          ini.GetValueF("XTBPot", "charge", xtb_options.charge);
 605→    }
 606→    // [ZBLPot]
 607→    if (potential_options.potential == PotType::ZBL) {
 608→      zbl_options.cut_inner =
 609→          ini.GetValueF("ZBLPot", "cut_inner", zbl_options.cut_inner);
 610→      zbl_options.cut_global =
 611→          ini.GetValueF("ZBLPot", "cut_global", zbl_options.cut_global);
 612→      if (zbl_options.cut_inner > zbl_options.cut_global) {
 613→        throw std::runtime_error(
 614→            "Switching function must begin before the global cutoff!");
 615→      }
 616→    }
 617→    // [SocketNWChemPot]
 618→    if (potential_options.potential == PotType::SocketNWChem) {
 619→      socket_nwchem_options.host =
 620→          ini.GetValue("SocketNWChemPot", "host", socket_nwchem_options.host);
 621→      socket_nwchem_options.port =
 622→          ini.GetValueL("SocketNWChemPot", "port", socket_nwchem_options.port);
 623→      socket_nwchem_options.mem_in_gb = ini.GetValueL(
 624→          "SocketNWChemPot", "mem_in_gb", socket_nwchem_options.mem_in_gb);
 625→      socket_nwchem_options.nwchem_settings =
 626→          ini.GetValue("SocketNWChemPot", "nwchem_settings",
 627→                       socket_nwchem_options.nwchem_settings);
 628→      socket_nwchem_options.unix_socket_path =
 629→          ini.GetValue("SocketNWChemPot", "unix_socket_path",
 630→                       socket_nwchem_options.unix_socket_path);
