1408→                      basin_hopping_options.significant_structure);
1409→    basin_hopping_options.displacement_algorithm =
1410→        toLowerCase(ini.GetValue("Basin Hopping", "displacement_algorithm",
1411→                                 basin_hopping_options.displacement_algorithm));
1412→    basin_hopping_options.displacement_distribution = toLowerCase(
1413→        ini.GetValue("Basin Hopping", "displacement_distribution",
1414→                     basin_hopping_options.displacement_distribution));
1415→    basin_hopping_options.swap_probability =
1416→        ini.GetValueF("Basin Hopping", "swap_probability",
1417→                      basin_hopping_options.swap_probability);
1418→    basin_hopping_options.jump_max = ini.GetValueL(
1419→        "Basin Hopping", "jump_max", basin_hopping_options.jump_max);
1420→    basin_hopping_options.jump_steps = ini.GetValueL(
1421→        "Basin Hopping", "jump_steps", basin_hopping_options.jump_steps);
1422→    basin_hopping_options.adjust_displacement =
1423→        ini.GetValueB("Basin Hopping", "adjust_displacement",
1424→                      basin_hopping_options.adjust_displacement);
1425→    basin_hopping_options.adjust_period = ini.GetValueL(
1426→        "Basin Hopping", "adjust_period", basin_hopping_options.adjust_period);
1427→    basin_hopping_options.adjust_fraction =
1428→        ini.GetValueF("Basin Hopping", "adjust_fraction",
1429→                      basin_hopping_options.adjust_fraction);
1430→    basin_hopping_options.target_ratio = ini.GetValueF(
1431→        "Basin Hopping", "target_ratio", basin_hopping_options.target_ratio);
1432→    basin_hopping_options.write_unique = ini.GetValueB(
1433→        "Basin Hopping", "write_unique", basin_hopping_options.write_unique);
1434→    basin_hopping_options.stop_energy = ini.GetValueF(
1435→        "Basin Hopping", "stop_energy", basin_hopping_options.stop_energy);
1436→
1437→    // [Global Optimization] //
1438→
1439→    global_optimization_options.move_method =
1440→        toLowerCase(ini.GetValue("Global Optimization", "move_method",
1441→                                 global_optimization_options.move_method));
1442→    global_optimization_options.decision_method =
1443→        toLowerCase(ini.GetValue("Global Optimization", "decision_method",
1444→                                 global_optimization_options.decision_method));
1445→    global_optimization_options.steps = ini.GetValueL(
1446→        "Global Optimization", "steps", global_optimization_options.steps);
1447→    global_optimization_options.beta = ini.GetValueF(
1448→        "Global Optimization", "beta", global_optimization_options.beta);
1449→    global_optimization_options.alpha = ini.GetValueF(
1450→        "Global Optimization", "alpha", global_optimization_options.alpha);
1451→    global_optimization_options.mdmin = ini.GetValueL(
1452→        "Global Optimization", "mdmin", global_optimization_options.mdmin);
1453→    global_optimization_options.target_energy =
1454→        ini.GetValueF("Global Optimization", "target_energy",
1455→                      global_optimization_options.target_energy);
1456→
1457→    // [BGSD] //
1458→
1459→    bgsd_options.alpha = ini.GetValueF("BGSD", "alpha", bgsd_options.alpha);
1460→    bgsd_options.beta = ini.GetValueF("BGSD", "beta", bgsd_options.beta);
1461→    bgsd_options.gradient_finite_difference =
1462→        ini.GetValueF("BGSD", "gradientfinitedifference",
1463→                      bgsd_options.gradient_finite_difference);
1464→    bgsd_options.grad2energy_convergence = ini.GetValueF(
1465→        "BGSD", "grad2energyconvergence", bgsd_options.grad2energy_convergence);
1466→    bgsd_options.grad2force_convergence = ini.GetValueF(
1467→        "BGSD", "grad2forceconvergence", bgsd_options.grad2force_convergence);
1468→
1469→    // [Monte Carlo] //
1470→
1471→    monte_carlo_options.step_size = ini.GetValueF(
1472→        "Monte Carlo", "step_size", monte_carlo_options.step_size);
1473→    monte_carlo_options.steps =
1474→        ini.GetValueI("Monte Carlo", "steps", monte_carlo_options.steps);
1475→
1476→    // Sanity Checks
1477→    if (parallel_replica_options.state_check_interval > dynamics_options.time &&
1478→        magic_enum::enum_name<JobType>(main_options.job) ==
1479→            "parallel_replica") {
1480→      SPDLOG_ERROR("[Parallel Replica] state_check_interval must be <= time");
1481→      error = 1;
1482→    }
1483→
1484→    // Check if an initial path exists without a specific non-linear initializer
1485→    if (!neb_options.initialization.input_path.empty() &&
1486→        neb_options.initialization.method == NEBInit::LINEAR) {
1487→      SPDLOG_WARN("[Nudged Elastic Band] 'initial_path_in' is provided, but "
1488→                  "'initializer' defaults to linear. "
1489→                  "Ensure this is intentional, as the loaded path will not be "
1490→                  "used without initializer set to file.");
1491→    }
1492→
1493→    if (saddle_search_options.dynamics.record_interval_input >
1494→        saddle_search_options.dynamics.state_check_interval_input) {
1495→      SPDLOG_ERROR("[Saddle Search] dynamics_record_interval must be <= "
1496→                   "dynamics_state_check_interval");
1497→      error = 1;
1498→    }
1499→
1500→    if (potential_options.potential == PotType::AMS ||
1501→        potential_options.potential == PotType::AMS_IO) {
1502→      if (ams_options.forcefield.empty() && ams_options.model.empty() &&
1503→          ams_options.xc.empty()) {
1504→        SPDLOG_ERROR("[AMS] Must provide atleast forcefield or model or xc");
1505→        error = 1;
1506→      }
1507→
1508→      if (!ams_options.forcefield.empty() && !ams_options.model.empty() &&
1509→          !ams_options.xc.empty()) {
1510→        SPDLOG_ERROR("[AMS] Must provide either forcefield or model");
1511→        error = 1;
1512→      }
1513→    }
1514→
1515→  } else {
1516→    SPDLOG_ERROR("Couldn't parse the ini file");
1517→    error = 1;
1518→  }
1519→
1520→  return error;
1521→}
