488→double MinModeSaddleSearch::getEigenvalue() {
489→  return minModeMethod->getEigenvalue();
490→}
491→
492→AtomMatrix MinModeSaddleSearch::getEigenvector() {
493→  return minModeMethod->getEigenvector();
494→}
