363→#endif
364→
365→    printSystemInfo();
366→
367→    // XXX(rg): Be more gentle here
368→    bool bundlingEnabled = false;
369→    int bundleSize = -1; // getBundleSize();
370→    if (bundleSize == 0) {
371→      bundleSize = 1;
372→    } else if (bundleSize == -1) {
373→      // Not using bundling
374→      bundleSize = 1;
375→      bundlingEnabled = false;
376→    }
377→
378→    std::vector<std::string> bundledFilenames;
379→    for (int i = 0; i < bundleSize; i++) {
380→      // Potential::fcalls = 0;
381→      // Potential::fcallsTotal = 0;
382→      if (bundleSize > 1)
383→        printf("Beginning Job %d of %d\n", i + 1, bundleSize);
384→      std::vector<std::string> unbundledFilenames;
385→      if (bundlingEnabled) {
386→        unbundledFilenames = unbundle(i);
387→      }
388→
389→      // check to see if parameters file exists before loading
390→      int error = 0;
391→      string config_file = helper_functions::getRelevantFile(
392→          parameters.main_options.iniFilename);
393→      printf("Loading parameter file %s\n", config_file.c_str());
394→      error = parameters.load(config_file);
395→
396→      if (error) {
397→        fprintf(stderr, "\nproblem loading parameter file, stopping\n");
398→        exit(1);
399→        abort();
400→      }
401→
402→      // Determine what type of job we are running according to the parameters
403→      // file.
404→      auto job =
405→          helper_functions::makeJob(std::make_unique<Parameters>(parameters));
406→      if (job == nullptr) {
407→        printf("error: Unknown job: %s\n",
408→               std::string{
409→                   magic_enum::enum_name<JobType>(parameters.main_options.job)}
410→                   .c_str());
411→        return 1;
412→      }
413→
414→      std::vector<std::string> filenames;
415→      try {
416→        filenames = job->run();
417→      } catch (int e) {
418→        SPDLOG_CRITICAL("[ERROR] job exited on error %d\n", e);
419→      }
420→
421→      filenames.push_back(std::string("client.log"));
422→
423→      // Finalize Timing Information
424→      auto end_time = std::chrono::steady_clock::now();
425→      std::chrono::duration<double> elapsed = end_time - start_time;
426→
427→      double utime = 0, stime = 0, rtime = 0;
428→      helper_functions::getTime(&rtime, &utime, &stime);
429→
430→      spdlog::info("Timing Information:");
431→      spdlog::info("  Real time: {:.3f} seconds", elapsed.count());
432→      spdlog::info("  User time: {:.3f} seconds", utime);
433→      spdlog::info("  System time: {:.3f} seconds", stime);
434→
435→      std::ofstream result_file("results.dat", std::ios::app);
436→      if (result_file.is_open()) {
437→        result_file << "time_seconds " << elapsed.count() << "\n";
438→#ifndef _WIN32
439→        result_file << "user_time " << utime << "\n";
440→        result_file << "system_time " << stime << "\n";
441→#endif
442→      } else {
443→        spdlog::error("Failed to write timing to results.dat");
444→      }
445→
446→      if (bundlingEnabled) {
447→        bundle(i, filenames, &bundledFilenames);
448→        deleteUnbundledFiles(unbundledFilenames);
449→      } else {
450→        bundledFilenames = filenames;
451→      }
452→    }
453→
454→#ifdef EONMPI
455→    if (client_standalone) {
456→      break;
457→    }
458→    MPI::COMM_WORLD.Isend(&path[0], 1024, MPI::CHAR, server_rank, 0);
459→
460→    // End of MPI while loop
461→  }
462→#endif
463→
464→#ifdef OSX
